. "$PSScriptRoot\..\Common.ps1"
try{ Require-Admin; $s=Read-Settings; $keep=@($s.KeepLocalAdmins); $changed=@(); $admins=Get-LocalGroupMember -Group 'Administrators'; foreach($m in $admins){$short=($m.Name -split '\\')[-1]; if($keep -notcontains $short -and $m.ObjectClass -eq 'User'){try{Disable-LocalUser -Name $short -ErrorAction Stop; $changed+=$m.Name}catch{}}}; New-Result -Step '09_LocalAdmin' -Enabled $true -Status '已停用非白名单本地管理员用户；不会处理域组/域用户' -Evidence @{Keep=$keep; Disabled=$changed} }catch{ New-Result -Step '09_LocalAdmin' -Success $false -Status '启用失败' -ErrorMessage $_.Exception.Message }